var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"흠...... 이렇게 하는 건가?","JPN":"ううむ……こうか？","ENG":"Hmm... Am I doing this correctly?","TWN":"呃……是這樣弄的嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"셀카는 그다지 찍어본 적이 없어서 잘 나오고 있는 건지 모르겠군.","JPN":"自撮りの経験がないから、ちゃんと撮れているかどうかわからんな。","ENG":"I've never been much of a selfie person. I have no idea what I'm doing.","TWN":"我沒有很常自拍，所以不知道拍得好不好。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"하지만 뭐, 아이돌 오디션 보는 것도 아닌데 너무 신경 쓸 필요는 없겠지?","JPN":"まあ、アイドルオーディションじゃあるまいし、そこまで気にすることないか。","ENG":"Well, It's not like I'm applying for a talent show. Who cares?","TWN":"但又不是偶像試鏡，應該沒什麼問題吧？"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IAN_EXTRA_NULL_NULL","text":{"KOREA":"어차피 내용이 중요한 거니까...... 대충 보라고, 시청자 여러분.","JPN":"何せ中身のほうが大事だからな……細かいことは気にしないでくれ、ご覧の皆さん。","ENG":"It's the content that matters. So suck it up if this turns out to be an eyesore.","TWN":"反正重要的是內容…… 觀眾朋友們就隨便看看吧。"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......누구야, 이건? 아저씨랑 좀 닮은 것 같은데.","JPN":"……これは誰？　おじさんに似てる気がするけど。","ENG":"Who's this? He looks quite similar to you.","TWN":"……這是誰啊？好像有點像大叔耶。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......내 형이다.","JPN":"……俺の兄貴だ。","ENG":"He's my brother.","TWN":"……他是我哥。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"형? 친형이라는 거야?","JPN":"兄貴？　実のお兄さんってこと？","ENG":"Your brother? You mean your biological brother?","TWN":"你哥？是親生哥哥嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 형은 아가씨처럼 카운터 능력자였지.","JPN":"ああ、兄貴は嬢ちゃんのようにカウンター能力者だったんだ。","ENG":"Yes. He was a Counter, just like you.","TWN":"是啊，我哥跟妳一樣是制裁者。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금은 교통사고로 죽었지만.","JPN":"交通事故で死んじまったけどな。","ENG":"He was killed in a traffic accident.","TWN":"雖然因為交通事故死了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 미, 미안해......","JPN":"あ、ご、ごめんなさい……","ENG":"S-sorry.","TWN":"抱、抱歉……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......교통사고라고요? 카운터 능력자가 말인가요?","JPN":"……交通事故？　カウンター能力者なのにですか？","ENG":"But... A traffic accident? Didn't you say he was a Counter?","TWN":"……你說交通事故？殺了一個制裁者？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 웃기지?","JPN":"そうさ、おかしいだろ？","ENG":"I did. Hilarious, huh?","TWN":"是啊，很搞笑吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 그게 정식 조사내용인 걸 어쩌겠어?","JPN":"けど、公式調査の結果がそうなんだからどうしようもねえ。","ENG":"But that's the official result of the investigation.","TWN":"但那就是調查結果，又有什麼辦法呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 몇 번이나 이의신청을 했지만 담당 조사관들은 들은 체도 하지 않더군.","JPN":"俺も何度も異議申し立てをしたが、担当調査官らはまったく聞く耳を持たなかったんだ。","ENG":"I filed an objection several times, but the investigators didn't even pretend to listen.","TWN":"雖然我對這件事提出了好幾次異議，但負責調查的官員們卻充耳不聞。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 입으로 말하긴 뭐하지만, 형은 꽤 괜찮은 인간이었어.","JPN":"俺が言うのも何なんだが、兄貴は結構いい奴でな。","ENG":"Though I say it myself, Ian was a decent human being.","TWN":"雖然我自己說有點那個啦，但我哥是個很好的人。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"카운터로서도, 학자로서도......","JPN":"カウンターとしても、学者としても……","ENG":"As a Counter, a scholar,","TWN":"不管是作為一個制裁者，還是一個學者……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};